// Exemplo em um componente de página de edição
import ClienteForm from '../..components/ClienteForm';

function PaginaEditarCliente() {
  const [cliente, setCliente] = useState(null);

  // Carrega os dados do cliente (ex: via API)
  useEffect(() => {
    const carregarCliente = async () => {
      const response = await api.getCliente(id);
      setCliente(response.data);
    };
    carregarCliente();
  }, []);

  const handleEditar = (dadosAtualizados) => {
    // Envia para a API
    api.updateCliente(id, dadosAtualizados);
  };

  if (!cliente) return <div>Carregando...</div>;

  return (
    <ClienteForm 
      cliente={cliente} 
      onSubmit={handleEditar} 
    />
  );
}
